import unreal, json
abp='/Game/Character/ABP_Bodycam'
print('is_abp:', unreal.AnimGraphService.is_anim_blueprint(abp))
print('parent:', unreal.AnimGraphService.get_parent_class(abp))
print('skeleton:', unreal.AnimGraphService.get_skeleton(abp))
for g in unreal.AnimGraphService.list_graphs(abp):
    print('GRAPH:', g.graph_name, g.graph_type, 'nodes=', g.node_count)
for m in unreal.AnimGraphService.list_state_machines(abp):
    print('MACHINE:', m.machine_name, 'states=', m.state_count)
    for s in unreal.AnimGraphService.list_states_in_machine(abp, m.machine_name):
        print('  STATE:', s.state_name, s.state_type, 'end=', s.is_end_state)
    for t in unreal.AnimGraphService.get_state_transitions(abp, m.machine_name):
        print('  TRANS:', t.source_state,'->',t.dest_state,'blend=',t.blend_duration,'rule=',t.rule_type,'summary=',t.rule_summary,'has_rule=',t.has_rule)
    r = unreal.AnimGraphService.validate_state_machine(abp, m.machine_name)
    print('  VALID:', r.is_valid, 'errors:', [str(e) for e in r.errors], 'warnings:', [str(w) for w in r.warnings])
# variables
try:
    vars_json = unreal.BlueprintService.get_variables(abp)
    print('VARS:', vars_json)
except Exception as e:
    print('vars err', e)
# anim graph nodes (look for modify bone chain)
try:
    nodes = unreal.AnimGraphService.get_nodes_in_graph(abp, 'AnimGraph')
    for n in nodes:
        print('NODE:', n)
except Exception as e:
    print('nodes err', e)
